INSERT INTO `apis` (`uuid`, `name`, `method`, `status`, `api_json`, `created_at`, `updated_at`) VALUES ('api_m2fqr3','未命名 API','GET','published','{\"uuid\": \"api_m2fqr3\", \"alias\": \"未命名 API\", \"blocks\": [], \"method\": \"GET\", \"request\": {\"body\": [], \"query\": [], \"header\": []}, \"response\": null}','2026-05-27 11:19:53.418440','2026-05-27 11:20:02.702000'),('login_employees','employees 登录接口','POST','draft','{\"uuid\": \"login_employees\", \"alias\": \"employees 登录接口\", \"blocks\": [{\"uuid\": \"read_user\", \"alias\": \"按邮箱读取用户\", \"inputs\": {\"table\": \"employees\", \"fields\": [\"id\", \"name\", \"email\", \"plan\", \"password_hash\"], \"conditions\": [{\"group\": false, \"fieldName\": \"email\", \"fieldValue\": {\"template\": \"{{request.body.email}}\"}, \"conditionType\": \"EQ\"}], \"datasource\": \"Mokelay\"}, \"outputs\": [{\"key\": \"data\", \"processors\": [\"is_not_null\"]}], \"functionName\": \"read\"}, {\"uuid\": \"set_user_session\", \"alias\": \"校验密码并写入 Session\", \"inputs\": {\"key\": \"user\", \"value\": {\"id\": {\"template\": \"{{blocks[\'read_user\'].outputs.data.id}}\"}, \"name\": {\"template\": \"{{blocks[\'read_user\'].outputs.data.name}}\"}, \"plan\": {\"template\": \"{{blocks[\'read_user\'].outputs.data.plan}}\"}, \"email\": {\"template\": \"{{blocks[\'read_user\'].outputs.data.email}}\"}}, \"password_check\": {\"template\": \"{{blocks[\'read_user\'].outputs.data.password_hash}}\", \"processors\": [{\"param\": [{\"template\": \"{{request.body.password}}\"}], \"processor\": \"hash_check\"}]}}, \"outputs\": [], \"functionName\": \"addSession\"}], \"method\": \"POST\", \"request\": {\"body\": [{\"key\": \"email\", \"processors\": [\"trim\", \"is_not_null\", \"email_check\", {\"param\": [255], \"processor\": \"max\"}]}, {\"key\": \"password\", \"processors\": [\"is_not_null\"]}], \"query\": [], \"header\": []}, \"response\": {\"user\": {\"id\": {\"template\": \"{{blocks[\'read_user\'].outputs.data.id}}\"}, \"name\": {\"template\": \"{{blocks[\'read_user\'].outputs.data.name}}\"}, \"plan\": {\"template\": \"{{blocks[\'read_user\'].outputs.data.plan}}\"}, \"email\": {\"template\": \"{{blocks[\'read_user\'].outputs.data.email}}\"}}}}','2026-05-25 16:57:25.547402','2026-05-25 16:57:25.546000');
